var dispIDs = ['PJ0301', 'PJ0302', 'PJ0304', 'PJ0305', 'PJ0306' ]; 
var dispDivIDs = ['#PJ0301', '#PJ0302', '#PJ0304', '#PJ0305', '#PJ0306']; 
