if (dispIDs[i] == displayingId){
$(dispDivIDs[i]).removeClass('dispoff');
$(dispDivIDs[i]).addClass('dispon');
}else{
$(dispDivIDs[i]).removeClass('dispon');
$(dispDivIDs[i]).addClass('dispoff');
}
}
}
function buttonMarker(){
var kbn=0;
