var reqID = getReqID(key);
reqPromises.push(Com.getRequestGet(reqID, gReqPrmsObject[key]));
}
var d = new $.Deferred();
$.when.apply(null, reqPromises)
.done(function () {
for (var i = 0; i < arguments.length; i++) {
jsonData[dispIDs[i]] = arguments[i];
}
d.resolve();
})
.fail(function(){
d.reject();
});
return d.promise();
}
